SELECT rating, COUNT(*) AS film_count
FROM film
GROUP BY rating;

SELECT store_id, COUNT(DISTINCT film_id) AS distinct_films
FROM inventory
GROUP BY store_id;

SELECT rating, AVG(rental_duration) AS average_rental_duration
FROM film
GROUP BY rating;

SELECT f.film_id, f.title, l.name AS original_language
FROM film f
JOIN language l ON f.original_language_id = l.language_id;

SELECT COUNT(*) AS not_returned_rentals
FROM rental
WHERE return_date IS NULL;
